import React, { useEffect, useState } from "react";
import Navbar from "../../components/Navbar";
import api from "../../api/axiosInstance";
import styles from "./AdminPages.module.css";

const ManagePackagesPage = () => {
  const [packages, setPackages] = useState([]);
  const [editId, setEditId] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    destination: "",
    duration: "",
    price: "",
    description: ""
  });

  // ===============================
  // LOAD PACKAGES
  // ===============================
  const loadPackages = async () => {
    try {
      const res = await api.get("/packages");
      setPackages(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    loadPackages();
  }, []);

  // ===============================
  // HANDLE INPUT
  // ===============================
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // ===============================
  // SUBMIT (ADD / UPDATE)
  // ===============================
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (editId) {
        await api.put(`/packages/${editId}`, formData);
        alert("✅ Package updated");
      } else {
        await api.post("/packages", formData);
        alert("✅ Package added");
      }

      setFormData({
        name: "",
        destination: "",
        duration: "",
        price: "",
        description: ""
      });

      setEditId(null);
      loadPackages();

    } catch (err) {
      console.error(err);
      alert("❌ Error saving package");
    }
  };

  // ===============================
  // EDIT
  // ===============================
  const handleEdit = async (id) => {
    try {
      const res = await api.get(`/packages/${id}`);

      setFormData({
        name: res.data.name || "",
        destination: res.data.destination || "",
        duration: res.data.duration || "",
        price: res.data.price || "",
        description: res.data.description || ""
      });

      setEditId(id);

      // scroll to form
      window.scrollTo({ top: 0, behavior: "smooth" });

    } catch (err) {
      console.error(err);
    }
  };

  // ===============================
  // DELETE
  // ===============================
  const handleDelete = async (id) => {
    if (!window.confirm("Delete this package?")) return;

    try {
      await api.delete(`/packages/${id}`);
      alert("🗑 Deleted successfully");
      loadPackages();
    } catch (err) {
      console.error(err);
      alert("❌ Delete failed");
    }
  };

  return (
    <>
      <Navbar />

      <div className={styles.container}>
        <h2>✈️ Manage Packages</h2>

        {/* ================= FORM ================= */}
        <form className={styles.left} onSubmit={handleSubmit}>
          <input
            name="name"
            placeholder="Package Name"
            value={formData.name}
            onChange={handleChange}
            required
          />

          <input
            name="destination"
            placeholder="Destination"
            value={formData.destination}
            onChange={handleChange}
          />

          <input
            name="duration"
            placeholder="Duration"
            value={formData.duration}
            onChange={handleChange}
          />

          <input
            name="price"
            placeholder="Price"
            value={formData.price}
            onChange={handleChange}
          />

          <textarea
            name="description"
            placeholder="Description"
            value={formData.description}
            onChange={handleChange}
          />

          <button className={styles.submitBtn}>
            {editId ? "Update Package" : "Add Package"}
          </button>
        </form>

        {/* ================= TABLE ================= */}
        <div className={styles.tableSection}>
          <h3>📦 Package History</h3>

          <table className={styles.table}>
            <thead>
              <tr>
                <th>Name</th>
                <th>Destination</th>
                <th>Duration</th>
                <th>Price</th>
                <th>Hotels</th>
                <th>Actions</th> {/* ✅ NEW */}
              </tr>
            </thead>

            <tbody>
              {packages.map((pkg) => (
                <tr key={pkg._id}>
                  <td>{pkg.name}</td>
                  <td>{pkg.destination || "-"}</td>
                  <td>{pkg.duration}</td>
                  <td>₹{pkg.price}</td>
                  <td>{pkg.hotels?.length || 0}</td>

                  {/* ✅ ACTION BUTTONS */}
                  <td>
                    <button
                      onClick={() => handleEdit(pkg._id)}
                      style={{
                        marginRight: "10px",
                        padding: "5px 10px",
                        cursor: "pointer"
                      }}
                    >
                      ✏️ Edit
                    </button>

                    <button
                      onClick={() => handleDelete(pkg._id)}
                      style={{
                        color: "white",
                        background: "red",
                        padding: "5px 10px",
                        border: "none",
                        cursor: "pointer"
                      }}
                    >
                      🗑 Delete
                    </button>
                  </td>

                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </>
  );
};

export default ManagePackagesPage;
